INSERT INTO `ai_music` VALUES (1, 1, '幸福的旋律', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'https://cdn1.suno.ai/image_73032eee-470e-46ff-a9bd-abb3e67b2934.png', 'http://test.yudao.iocoder.cn/12f3702f71bf3d1e7eadbc0d611afca58868b783fe9c8b30bf913b4aa74e3af1.mp3', 'https://cdn1.suno.ai/73032eee-470e-46ff-a9bd-abb3e67b2934.mp4', 20, '来一首快乐的歌曲', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'Suno', 0, 'chirp-v3.5', 2, '[\"pop\"]', 145.96, b'0', '73032eee-470e-46ff-a9bd-abb3e67b2934', NULL, '1', '2024-06-27 21:08:42', '1', '2024-07-05 01:30:16', b'0', 1);
INSERT INTO `ai_music` VALUES (2, 1, '幸福的旋律', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'http://test.yudao.iocoder.cn/e8e50a3fd176756069c7cd2117d32b3eddec58c2439d1e8faf8f08d23a7fd992.png', 'https://cdn1.suno.ai/727a5f9b-102d-438a-909a-13f31c433dbb.mp3', 'http://test.yudao.iocoder.cn/bb48fe2b19211d80f3522b2528b12dad6f72a95c674cff4a6b8c0396ed954a4b.mp4', 20, '来一首快乐的歌曲', '[Verse]\n阳光撒满了街道\n梦想在心中起跑\n\n[Verse 2]\n快乐随着风在笑\n青春在时光里跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好\n\n[Verse 3]\n花开在晨曦微笑\n心跳伴随音符跳\n\n[Bridge]\n让烦恼都退烧\n世界只剩心跳\n\n[Chorus]\n哼着熟悉的歌谣\n幸福就在我怀抱\n奔向未来的征兆\n一起创造美好', 'Suno', 0, 'chirp-v3.5', 2, '[\"pop\"]', 121.48, b'0', '727a5f9b-102d-438a-909a-13f31c433dbb', NULL, '1', '2024-06-27 21:08:42', '1', '2024-07-05 01:30:16', b'0', 1);
INSERT INTO `ai_music` VALUES (3, 1, '快乐的时光', '[Verse]\n阳光洒在天空下\n笑脸藏不住啊\n[Verse 2]\n伙伴们聚在一起\n欢笑声不停歇\n[Chorus]\n快乐就在眼前\n一起尽情欢笑\n跳舞不停的旋转\n快乐围绕着我们\n[Verse 3]\n时间在快乐中飞\n烦恼都忘掉了\n[Bridge]\n闭上眼用心感觉\n幸福在心中荡漾\n[Chorus]\n快乐就在眼前\n一起尽情欢笑\n跳舞不停的旋转\n快乐围绕着我们', 'https://cdn1.suno.ai/image_c300a71d-237d-4d82-a884-00ccab42f10e.png', 'https://cdn1.suno.ai/c300a71d-237d-4d82-a884-00ccab42f10e.mp3', 'https://cdn1.suno.ai/c300a71d-237d-4d82-a884-00ccab42f10e.mp4', 20, '来一首快乐的歌曲', '[Verse]\n阳光洒在天空下\n笑脸藏不住啊\n\n[Verse 2]\n伙伴们聚在一起\n欢笑声不停歇\n\n[Chorus]\n快乐就在眼前\n一起尽情欢笑\n跳舞不停的旋转\n快乐围绕着我们\n\n[Verse 3]\n时间在快乐中飞\n烦恼都忘掉了\n\n[Bridge]\n闭上眼用心感觉\n幸福在心中荡漾\n\n[Chorus]\n快乐就在眼前\n一起尽情欢笑\n跳舞不停的旋转\n快乐围绕着我们', 'Suno', 0, 'chirp-v3.5', 2, '[\"pop\"]', NULL, b'0', 'c300a71d-237d-4d82-a884-00ccab42f10e', NULL, '1', '2024-06-27 21:12:14', '1', '2024-07-05 01:30:16', b'0', 1);
