INSERT INTO `ai_music` VALUES (35, 1, 'Sunshine in My Soul', '[Verse]\nSunny days no cloud in sight\nEvery step feels so light\nLaughter echoes all around\nFeet moving to the sound\n[Verse 2]\nColors bright like neon lights\nHeart\'s glowing with delight\nJoy fills every single street\nDancing to a happy beat\n[Chorus]\nSunshine in my soul today\nWorries all just float away\nLiving in this moment bright\nEverything\'s gonna be alright', 'https://cdn1.suno.ai/image_ce3e7d91-bce0-4163-a66d-f58dd41a695e.png', 'https://cdn1.suno.ai/None.mp3', '', 30, 'happy music', NULL, 'Suno', 0, 'chirp-v3', 1, '[\"pop feel-good\"]', NULL, b'0', 'ce3e7d91-bce0-4163-a66d-f58dd41a695e', NULL, '1', '2024-07-04 23:26:20', '1', '2024-07-05 01:30:16', b'0', 1);
