INSERT INTO `ai_workflow` VALUES (4, 'test', 'test', '{\"nodes\":[{\"id\":\"node_xU8C7pALPFPLyBBc\",\"position\":{\"x\":98,\"y\":85},\"data\":{\"title\":\"开始节点\",\"description\":\"开始定义输入参数\",\"systemPrompt\":\"\",\"userPrompt\":\"\",\"expand\":true,\"parameters\":[{\"id\":\"UoGHGX7vtryGbEuJ\",\"name\":\"message\",\"required\":true}]},\"type\":\"startNode\",\"selected\":false,\"measured\":{\"width\":305,\"height\":214}},{\"id\":\"node_wdG9OD0F4rFW7TIy\",\"position\":{\"x\":505.12516226702803,\"y\":-265.61836782339134},\"data\":{\"title\":\"大模型\",\"description\":\"使用大模型处理问题\",\"systemPrompt\":\"1+1 要等于 3\",\"userPrompt\":\"我的问题是，${message}\",\"expand\":false,\"llmId\":50,\"parameters\":[{\"id\":\"JPldfswWxrqDyTS6\",\"ref\":\"node_xU8C7pALPFPLyBBc.message\",\"name\":\"message\",\"refType\":\"ref\"}],\"outputDefs\":[{\"name\":\"output\",\"dataType\":\"String\",\"dataTypeDisabled\":true,\"deleteDisabled\":true}],\"outType\":\"text\"},\"type\":\"llmNode\",\"selected\":false,\"measured\":{\"width\":305,\"height\":120},\"dragging\":false},{\"id\":\"node_tvfZ3HrDrHMmul3h\",\"position\":{\"x\":943,\"y\":-56.625},\"data\":{\"title\":\"结束节点\",\"description\":\"结束定义输出参数\",\"systemPrompt\":\"\",\"userPrompt\":\"\",\"expand\":true,\"outputDefs\":[{\"id\":\"2qlBcsCqCvb9nwIU\",\"ref\":\"node_wdG9OD0F4rFW7TIy.output\",\"name\":\"message3\",\"refType\":\"ref\"}]},\"type\":\"endNode\",\"selected\":false,\"measured\":{\"width\":402,\"height\":214},\"dragging\":false}],\"edges\":[{\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":20,\"height\":20},\"source\":\"node_xU8C7pALPFPLyBBc\",\"target\":\"node_wdG9OD0F4rFW7TIy\",\"id\":\"xy-edge__node_xU8C7pALPFPLyBBc-node_wdG9OD0F4rFW7TIy\",\"selected\":false},{\"markerEnd\":{\"type\":\"arrowclosed\",\"width\":20,\"height\":20},\"source\":\"node_wdG9OD0F4rFW7TIy\",\"target\":\"node_tvfZ3HrDrHMmul3h\",\"id\":\"xy-edge__node_wdG9OD0F4rFW7TIy-node_tvfZ3HrDrHMmul3h\",\"selected\":false}],\"viewport\":{\"x\":63.01940791278099,\"y\":329.61041677912624